css:
.loader {color: var(--loader-color, #dc2626);
  --loader-secondary-color: #f97316;
  --loader-bg: #ffffff;
   display: inline-flex;
   gap: 5px;
   animation: l2-0 1s infinite linear;
}
.loader:before, .loader:after  {
  content: "";
   width: 35px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px inset currentColor;
   animation: l2-1 1s infinite linear both;
}
.loader:after  {
  animation-direction:reverse;
}
@keyframes l2-0 {
  0% {transform:rotate(0deg)}
80%, 100%{transform:rotate(180deg)}
}
@keyframes l2-1 {
  0%, 20% {border-radius:0}
80%, 100% {border-radius:50%}
}
